int total = 120;
int discount = 0;

if (total > 100)
{
    discount = total * 20 / 100;
}
else if (total == 100)
{
    discount = total * 10 / 100;
}
else
{
    discount = total * 5 / 100;
}

total = total - discount;

Console.WriteLine("Final purchase price: " + total);

